+// TestVersionComparison tests the version comparison logic
+func TestVersionComparison(t *testing.T) {
+	tests := []struct {
+		current   string
+		latest    string
+		wantNewer bool
+	}{
+		{"1.0.0", "1.1.0", true},
+		{"1.0.0", "1.0.1", true},
+		{"1.0.0", "2.0.0", true},
+		{"1.0.0", "1.0.0", false},
+		{"1.1.0", "1.0.0", false},
+		{"2.0.0", "1.9.9", false},
+		{"dev", "1.0.0", true},
+		{"", "1.0.0", true},
+		{"v1.0.0", "v1.1.0", true},
+		{"1.0", "1.0.1", true},
+		{"1.0.0-beta", "1.0.0", false}, // normalizeVersion strips suffix, so they're equal
+	}
+
+	for _, tt := range tests {
+		t.Run(tt.current+"_vs_"+tt.latest, func(t *testing.T) {
+			got := isNewerVersion(tt.current, tt.latest)
+			if got != tt.wantNewer {
+				t.Errorf("isNewerVersion(%q, %q) = %v, want %v", tt.current, tt.latest, got, tt.wantNewer)
+			}
+		})
+	}
+}
